import{_ as e,o as t,c as a,a5 as o}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"学习记录 #0017：并机与冗余设计——高可用UPS系统的基石","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0017：并机与冗余设计——高可用UPS系统的基石","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第17课 — 并机与冗余设计（Phase 3系统集成） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0017-parallel-redundancy.md","filePath":"content/power/archive/old-learning-records/0017-parallel-redundancy.md","lastUpdated":null}'),n={name:"content/power/archive/old-learning-records/0017-parallel-redundancy.md"};function l(s,r,i,c,d,g){return t(),a("div",null,[...r[0]||(r[0]=[o('<h1 id="学习记录-0017-并机与冗余设计——高可用ups系统的基石" tabindex="-1">学习记录 #0017：并机与冗余设计——高可用UPS系统的基石 <a class="header-anchor" href="#学习记录-0017-并机与冗余设计——高可用ups系统的基石" aria-label="Permalink to &quot;学习记录 #0017：并机与冗余设计——高可用UPS系统的基石&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第17课 — 并机与冗余设计（Phase 3系统集成） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>并机两大需求</strong>：扩容（多台并机达到更大功率）+冗余（N+1容错）</li><li><strong>三种均流方法</strong>：下垂法(3~5%,最简单)、主从法(1~2%)、平均电流法(1~3%,最常用)</li><li><strong>下垂法</strong>：Vref=Vnom-K×Iout，K=1~3%×Vnom/Inom</li><li><strong>并机同步</strong>：相位差&lt;1°（55.6μs@50Hz），否则环流烧器件</li><li><strong>CAN并机通信</strong>：相位角1kHz广播+模块状态1kHz+故障事件触发</li><li><strong>N+1冗余</strong>：3台50kVA供100kVA负载，冗余度50%，可承受1台故障</li><li><strong>故障降级</strong>：均流线故障→自动切换下垂法，不停止运行</li><li><strong>调试5步法</strong>：单机→通信→同步→均流→冗余</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第18课：保护机制设计</p>',6)])])}const h=e(n,[["render",l]]);export{u as __pageData,h as default};
